#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

int64_t powmod(int64_t base, int64_t exponent, int64_t mod) {
    int64_t result = 1;
    while (exponent > 0) {
        if (exponent % 2 == 1) {
            result = (result * base) % mod;
        }
        exponent /= 2;
        base = (base * base) % mod;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int64_t N, C;
        scanf("%lld %lld", &N, &C);
        int64_t result = powmod(C, 5 * N * N, MOD);
        printf("%lld\n", result);
    }
    return 0;
}

